const APP_VERSION = "permuta_v5";
const DB = {
  async get(key, shared=false){
    try{
      const k = shared ? `shared_${key}` : `user_${key}`;
      const val = localStorage.getItem(k);
      return val ? JSON.parse(val) : null;
    }catch{return null;}
  },
  async set(key, val, shared=false){
    try{
      const k = shared ? `shared_${key}` : `user_${key}`;
      localStorage.setItem(k, JSON.stringify(val));
    }catch{}
  },
  clearOldData(){
    const saved = localStorage.getItem("app_version");
    if(saved !== APP_VERSION){
      const keysToRemove = [];
      for(let i=0; i<localStorage.length; i++){
        const k = localStorage.key(i);
        if(k && (k.includes("srvs:") || k.includes("users:") || k.includes("chats") || k.includes("auth:"))){
          keysToRemove.push(k);
        }
      }
      keysToRemove.forEach(k => localStorage.removeItem(k));
      localStorage.setItem("app_version", APP_VERSION);
    }
  }
};

