function ago(ts){const d=(Date.now()-ts)/1000;if(d<60)return"agora";if(d<3600)return`${Math.floor(d/60)}min`;if(d<86400)return`${Math.floor(d/3600)}h`;if(d<604800)return`${Math.floor(d/86400)}d`;return`${Math.floor(d/604800)}sem`;}
function normCity(c){
  if(!c)return"";
  return c.trim().toLowerCase()
    .normalize("NFD").replace(/[̀-ͯ]/g,"")
    .replace(/\s*-\s*[a-z]{2}\s*$/i,"")
    .replace(/\s+/g," ").trim();
}
function cityMatch(desired, atual){
  const d=normCity(desired);
  const a=normCity(atual);
  if(!d||!a)return false;
  return d===a||a.startsWith(d)||d.startsWith(a)||a.includes(d)||d.includes(a);
}
function checkMatch(a,b){
  if(!a||!b)return false;
  const aDesejadas=(a.cidadesDesejadas||"").split(",");
  const bDesejadas=(b.cidadesDesejadas||"").split(",");
  const aAtual=a.cidadeAtual||"";
  const bAtual=b.cidadeAtual||"";
  const aWantsB=aDesejadas.some(c=>cityMatch(c,bAtual));
  const bWantsA=bDesejadas.some(c=>cityMatch(c,aAtual));
  return aWantsB&&bWantsA;
}
function getUserMatches(user,srvs){
  const me=srvs.find(s=>s.id===user.id);
  if(!me)return[];
  const matches=srvs.filter(o=>o.id!==user.id&&checkMatch(me,o));
  return matches;
}

