              <div style={{width:42,height:42,borderRadius:12,background:ac(m.nome),display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontWeight:800,fontSize:".88rem",flexShrink:0}}>{ini(m.nome)}</div>
