export default function App(){
  const [user,setUser]=useState(null);
  const [srvs,setSrvs]=useState([]);
  const [tab,setTab]=useState("buscar");
  const [toast,setToast]=useState(null);
  const [loading,setLoading]=useState(true);
  const [chatTarget,setChatTarget]=useState(null);
  const [allChats,setAllChats]=useState({});
  const [unread,setUnread]=useState({});
  const [showMatchAlert,setShowMatchAlert]=useState(false);
  const [seenMatches,setSeenMatches]=useState([]);

  useEffect(()=>{(async()=>{
    // Versão do banco — mude este valor para forçar reset para todos os usuários
    const DB_VERSION="v4";

    // Verifica versão no storage compartilhado
    const savedVersion=await DB.get("db:version:2026",true);

    if(savedVersion!==DB_VERSION){
      // Nova versão detectada — reseta dados compartilhados para todos
      await DB.set("srvs:trt:2026",DADOS_REAIS,true);
      await DB.set("db:version:2026",DB_VERSION,true);
    }

    // Carrega lista atualizada
    const list=await DB.get("srvs:trt:2026",true)||DADOS_REAIS;
    setSrvs(list);

    // Carrega usuário logado (armazenamento individual)
    const u=await DB.get("auth:current:2026");
    if(u)setUser(u);

    setLoading(false);
  })();},[]);

  useEffect(()=>{
    if(!user||srvs.length===0)return;
    const myM=getUserMatches(user,srvs);
    const newOnes=myM.filter(m=>!seenMatches.includes(m.id));
    if(newOnes.length>0){setShowMatchAlert(true);setSeenMatches(myM.map(m=>m.id));}
  },[user,srvs]);

  useEffect(()=>{if(!user)return;(async()=>{
    const c=await DB.get(`chats2026:${user.id}`)||{};
    setAllChats(c);
    const ur={};Object.entries(c).forEach(([k,ms])=>{const n=ms.filter(m=>m.from!==user.id&&!m.read).length;if(n>0)ur[k]=n;});
    setUnread(ur);
  })();},[user]);

  const showToast=(msg,tipo="ok")=>{setToast({msg,tipo});setTimeout(()=>setToast(null),3500);};
  const saveSrvs=async(list)=>{setSrvs(list);await DB.set("srvs:trt:2026",list,true);};
  const totalUR=Object.values(unread).reduce((a,b)=>a+b,0);
  const myMatches=user?getUserMatches(user,srvs):[];

  if(loading)return(<div style={{minHeight:"100vh",background:"linear-gradient(135deg,#1E3A8A,#2563EB)",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:16}}><GS/><img src={LOGO} style={{width:130,height:130,objectFit:"contain"}}/><p style={{color:"white",fontWeight:700,fontSize:"1rem",marginTop:4}}>você, de volta para casa</p><div style={{width:40,height:4,borderRadius:2,background:"rgba(255,255,255,.3)",overflow:"hidden"}}><div style={{height:"100%",background:"white",borderRadius:2,animation:"lb 1.2s ease infinite"}}/></div></div>);
  if(!user)return(<AuthScreen onAuth={u=>{setUser(u);DB.set("auth:current:2026",u);}} showToast={showToast}/>);

  return(
    <div style={{minHeight:"100vh",background:"#EEF2FF",fontFamily:"'DM Sans',sans-serif"}}>
      <GS/>
      {showMatchAlert&&myMatches.length>0&&<MatchAlertModal matches={myMatches} onClose={()=>setShowMatchAlert(false)} onChat={s=>{setChatTarget(s);setTab("chat");setShowMatchAlert(false);}}/>}
      <Header user={user} tab={tab} setTab={setTab} totalUR={totalUR} matchCount={myMatches.length} srvCount={srvs.length} onLogout={()=>{setUser(null);DB.set("auth:current:2026",null);setChatTarget(null);}}/>
      <div style={{maxWidth:900,margin:"0 auto",padding:"22px 16px 80px"}}>
        {tab==="buscar"&&<BuscarTab srvs={srvs} user={user} showToast={showToast} onChat={s=>{setChatTarget(s);setTab("chat");}} unread={unread}/>}
        {tab==="matches"&&<MatchesTab myMatches={myMatches} user={user} srvs={srvs} onChat={s=>{setChatTarget(s);setTab("chat");}} unread={unread}/>}
        {tab==="cadastrar"&&<CadastrarTab user={user} srvs={srvs} saveSrvs={saveSrvs} showToast={showToast} setTab={setTab}/>}
        {tab==="concretizadas"&&<ConcretizadasTab/>}
        {tab==="chat"&&<ChatTab user={user} srvs={srvs} chatTarget={chatTarget} setChatTarget={setChatTarget} allChats={allChats} setAllChats={setAllChats} unread={unread} setUnread={setUnread}/>}
        {tab==="perfil"&&<PerfilTab user={user} setUser={setUser} srvs={srvs} saveSrvs={saveSrvs} showToast={showToast} myMatches={myMatches}/>}
      </div>
      {toast&&<Toast msg={toast.msg} tipo={toast.tipo}/>}
    </div>
  );
}

function AuthScreen({onAuth,showToast}){
  const [mode,setMode]=useState("login");
  const [f,setF]=useState({nome:"",email:"",senha:"",cargo:"",manter:false});
  const [busy,setBusy]=useState(false);
  const upd=(k,v)=>setF(p=>({...p,[k]:v}));

  const doLogin=async()=>{
    if(!f.email||!f.senha)return showToast("Preencha e-mail e senha.","erro");
    setBusy(true);
    const users=await DB.get("users:trt:2026",true)||{};
    const u=Object.values(users).find(u=>u.email===f.email&&u.senha===f.senha);
    setBusy(false);
    if(!u)return showToast("E-mail ou senha incorretos.","erro");
    if(f.manter)await DB.set("auth:current:2026",u);
    onAuth(u);
  };
  const doReg=async()=>{
    if(!f.nome||!f.email||!f.senha||!f.cargo)return showToast("Preencha todos os campos.","erro");
    if(f.senha.length<6)return showToast("Senha mínima: 6 caracteres.","erro");
    setBusy(true);
    const users=await DB.get("users:trt:2026",true)||{};
    if(Object.values(users).find(u=>u.email===f.email)){setBusy(false);return showToast("E-mail já cadastrado.","erro");}
    const nu={id:`u_${Date.now()}`,nome:f.nome,email:f.email,senha:f.senha,cargo:f.cargo,ts:Date.now()};
    users[nu.id]=nu;await DB.set("users:trt:2026",users,true);
    if(f.manter)await DB.set("auth:current:2026",nu);
    setBusy(false);showToast("Conta criada! 🎉");onAuth(nu);
  };

  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(150deg,#1E3A8A,#2563EB 55%,#3B82F6)",display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <GS/>
      <div style={{width:"100%",maxWidth:430}}>
        <div style={{textAlign:"center",marginBottom:26}}>
          <img src={LOGO} style={{width:160,height:160,objectFit:"contain",marginBottom:10}}/>
          <h1 style={{color:"white",fontWeight:700,fontSize:"1.3rem",letterSpacing:"-.01em",marginTop:8}}>você, de volta para casa</h1>
          <p style={{color:"#BFDBFE",fontSize:".85rem",marginTop:4,fontStyle:"italic"}}></p>
          <p style={{color:"rgba(255,255,255,.7)",fontSize:".78rem",marginTop:4}}>Plataforma de Permuta de Lotação — Justiça do Trabalho</p>
        </div>
        <div style={{background:"white",borderRadius:22,padding:"28px 24px",boxShadow:"0 24px 60px rgba(0,0,0,.25)"}}>
          <div style={{display:"flex",background:"#EEF2FF",borderRadius:12,padding:4,marginBottom:20}}>
            {[["login","Entrar"],["register","Criar conta"]].map(([m,l])=>(
              <button key={m} onClick={()=>setMode(m)} style={{flex:1,padding:"9px 0",borderRadius:9,border:"none",cursor:"pointer",background:mode===m?"white":"transparent",color:mode===m?"#1E3A8A":"#6B7280",fontWeight:700,fontSize:".88rem",fontFamily:"'DM Sans',sans-serif",boxShadow:mode===m?"0 2px 8px rgba(0,0,0,.1)":"none",transition:"all .2s"}}>{l}</button>
            ))}
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            {mode==="register"&&<FL label="Nome completo"><input className="inp" placeholder="Maria da Silva" value={f.nome} onChange={e=>upd("nome",e.target.value)}/></FL>}
            <FL label="E-mail funcional"><input className="inp" type="email" placeholder="nome@trt1.jus.br" value={f.email} onChange={e=>upd("email",e.target.value)}/></FL>
            <FL label="Senha"><input className="inp" type="password" placeholder="••••••••" value={f.senha} onChange={e=>upd("senha",e.target.value)}/></FL>
            {mode==="register"&&<FL label="Cargo"><select className="inp" value={f.cargo} onChange={e=>upd("cargo",e.target.value)}><option value="">Selecione...</option>{CARGOS.filter(c=>c!=="Todos").map(o=><option key={o}>{o}</option>)}</select></FL>}
          </div>
          <label style={{display:"flex",alignItems:"center",gap:8,marginTop:14,cursor:"pointer",fontSize:".83rem",color:"#374151",fontWeight:500}}>
            <input type="checkbox" className="chk" checked={f.manter} onChange={e=>upd("manter",e.target.checked)}/>
            Manter-me conectado
          </label>
          <button className="bp" onClick={mode==="login"?doLogin:doReg} disabled={busy} style={{width:"100%",marginTop:16,padding:"13px 0",fontSize:"1rem"}}>{busy?"Aguarde...":(mode==="login"?"Entrar →":"Criar conta →")}</button>
          <p style={{textAlign:"center",marginTop:12,fontSize:".74rem",color:"#9CA3AF"}}>Exclusivo para servidores da Justiça do Trabalho</p>
        </div>
      </div>
    </div>
  );
}

