function CadastrarTab({user,srvs,saveSrvs,showToast,setTab}){
  const ex=srvs.find(s=>s.id===user.id);
  const [f,setF]=useState({trtAtual:ex?.trtAtual||"",cidadeAtual:ex?.cidadeAtual||"",trtDesejado:ex?.trtDesejado||"",cidadesDesejadas:ex?.cidadesDesejadas||"",aceitaOutras:ex?.aceitaOutras||"Não",telefone:ex?.telefone||""});
  const [saved,setSaved]=useState(false);
  const upd=(k,v)=>setF(p=>({...p,[k]:v}));
  const trtOpts=TRTS.filter(t=>t!=="Todos");
  const save=async()=>{
    if(!f.trtAtual||!f.cidadeAtual||!f.trtDesejado||!f.cidadesDesejadas)return showToast("Preencha todos os campos obrigatórios.","erro");
    const entry={id:user.id,nome:user.nome,email:user.email,cargo:user.cargo,...f,ts:ex?.ts||Date.now()};
    await saveSrvs(ex?srvs.map(s=>s.id===user.id?entry:s):[entry,...srvs]);
    showToast(ex?"Permuta atualizada! ✓":"Permuta publicada! 🎉");setSaved(true);setTimeout(()=>{setSaved(false);setTab("buscar");},2000);
  };
  const remove=async()=>{await saveSrvs(srvs.filter(s=>s.id!==user.id));showToast("Permuta removida.");setF({trtAtual:"",cidadeAtual:"",trtDesejado:"",cidadesDesejadas:"",aceitaOutras:"Não",telefone:""});};
  return(
    <div className="fi">
      <div className="card" style={{padding:"26px 24px",maxWidth:560,margin:"0 auto"}}>
        <h2 style={{fontWeight:800,color:"#0F172A",fontSize:"1.1rem",marginBottom:4}}>{ex?"✏️ Editar minha permuta":"➕ Publicar minha permuta"}</h2>
        <p style={{color:"#64748B",fontSize:".83rem",marginBottom:18}}>{ex?"Atualize suas informações.":"Informe seus dados para ser encontrado."}</p>
        <div style={{background:"#EEF2FF",borderRadius:12,padding:"11px 14px",marginBottom:18}}><p style={{fontSize:".8rem",color:"#1E3A8A",fontWeight:600}}>👤 {user.nome} • {user.cargo} • {user.email}</p></div>
        <div style={{display:"flex",flexDirection:"column",gap:14}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <FL label="TRT atual *"><select className="inp" value={f.trtAtual} onChange={e=>upd("trtAtual",e.target.value)}><option value="">Selecione...</option>{trtOpts.map(t=><option key={t} value={t.split(" ")[0]}>{t}</option>)}</select></FL>
            <FL label="Cidade atual *"><input className="inp" placeholder="Ex: Rio de Janeiro - RJ" value={f.cidadeAtual} onChange={e=>upd("cidadeAtual",e.target.value)}/></FL>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <FL label="TRT desejado *"><select className="inp" value={f.trtDesejado} onChange={e=>upd("trtDesejado",e.target.value)}><option value="">Selecione...</option>{trtOpts.map(t=><option key={t} value={t.split(" ")[0]}>{t}</option>)}</select></FL>
            <FL label="Cidade(s) desejada(s) *"><input className="inp" placeholder="Ex: Niterói - RJ" value={f.cidadesDesejadas} onChange={e=>upd("cidadesDesejadas",e.target.value)}/></FL>
          </div>
          <FL label="Aceita outras cidades no mesmo TRT?"><select className="inp" value={f.aceitaOutras} onChange={e=>upd("aceitaOutras",e.target.value)}><option>Não</option><option>Sim</option></select></FL>
          <FL label="Telefone (opcional)"><input className="inp" placeholder="Ex: 21999999999" value={f.telefone} onChange={e=>upd("telefone",e.target.value)}/></FL>
        </div>
        <button className="bp" onClick={save} style={{width:"100%",marginTop:18,padding:"12px 0",fontSize:".95rem"}}>{saved?"✓ Salvo!":ex?"Atualizar permuta":"Publicar permuta →"}</button>
        {ex&&<button onClick={remove} style={{width:"100%",marginTop:10,padding:"10px 0",background:"transparent",border:"1.5px solid #FCA5A5",color:"#EF4444",borderRadius:10,cursor:"pointer",fontWeight:600,fontSize:".86rem",fontFamily:"'DM Sans',sans-serif"}}>🗑 Remover minha permuta</button>}
      </div>
    </div>
  );
}

function ChatTab({user,srvs,chatTarget,setChatTarget,allChats,setAllChats,unread,setUnread}){
  const [txt,setTxt]=useState("");const botRef=useRef();
  const others=srvs.filter(s=>s.id!==user.id);
  const convKey=chatTarget?cvId(user.id,chatTarget.id):null;
  const messages=convKey?(allChats[convKey]||[]):[];
  useEffect(()=>{if(!chatTarget||!convKey)return;const updated={...allChats};if(updated[convKey]){updated[convKey]=updated[convKey].map(m=>({...m,read:true}));setAllChats(updated);DB.set(`chats2026:${user.id}`,updated);setUnread(p=>{const n={...p};delete n[convKey];return n;});}},[chatTarget]);
  useEffect(()=>{botRef.current?.scrollIntoView({behavior:"smooth"});},[messages]);
  const send=async()=>{
    if(!txt.trim()||!chatTarget)return;
    const msg={from:user.id,text:txt.trim(),ts:Date.now(),read:false};
    const updated={...allChats,[convKey]:[...(allChats[convKey]||[]),msg]};
    setAllChats(updated);await DB.set(`chats2026:${user.id}`,updated);
    const their=await DB.get(`chats2026:${chatTarget.id}`)||{};their[convKey]=[...(their[convKey]||[]),msg];await DB.set(`chats2026:${chatTarget.id}`,their);setTxt("");
  };
  return(
    <div className="fi" style={{display:"flex",gap:12,height:"calc(100vh - 158px)",minHeight:400}}>
      <div className="card" style={{width:210,flexShrink:0,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        <div style={{padding:"12px 14px 10px",borderBottom:"1px solid #E2E8F0"}}><p style={{fontWeight:700,color:"#0F172A",fontSize:".88rem"}}>💬 Servidores</p></div>
        <div style={{flex:1,overflowY:"auto"}}>
          {others.map(s=>{const ck=cvId(user.id,s.id);const msgs=allChats[ck]||[];const ur=unread[ck]||0;const isAct=chatTarget?.id===s.id;return(
            <div key={s.id} onClick={()=>setChatTarget(s)} style={{padding:"10px 12px",cursor:"pointer",display:"flex",gap:9,alignItems:"center",background:isAct?"#EEF2FF":"transparent",borderLeft:isAct?"3px solid #2563EB":"3px solid transparent",transition:"all .15s"}}>
              <div style={{width:32,height:32,borderRadius:9,background:ac(s.nome),display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontWeight:800,fontSize:".7rem",flexShrink:0}}>{ini(s.nome)}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <p style={{fontWeight:700,color:"#0F172A",fontSize:".79rem",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.nome.split(" ")[0]}</p>
                  {ur>0&&<span style={{background:"#2563EB",color:"white",borderRadius:10,padding:"1px 5px",fontSize:".62rem",fontWeight:800,flexShrink:0}}>{ur}</span>}
                </div>
                <p style={{fontSize:".69rem",color:"#94A3B8",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{msgs.length>0?msgs[msgs.length-1].text:`${s.trtAtual} → ${s.trtDesejado}`}</p>
              </div>
            </div>
          );})}
        </div>
      </div>
      <div className="card" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {!chatTarget?(<div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:10,color:"#94A3B8"}}><div style={{fontSize:36}}>💬</div><p style={{fontWeight:600}}>Selecione um servidor</p></div>):(
          <>
            <div style={{padding:"12px 16px",borderBottom:"1px solid #E2E8F0",display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
              <div style={{width:36,height:36,borderRadius:10,background:ac(chatTarget.nome),display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontWeight:800,fontSize:".8rem",flexShrink:0}}>{ini(chatTarget.nome)}</div>
              <div style={{flex:1}}><p style={{fontWeight:700,color:"#0F172A",fontSize:".9rem"}}>{chatTarget.nome}</p><p style={{fontSize:".71rem",color:"#64748B"}}>{chatTarget.cargo} • {chatTarget.trtAtual} → {chatTarget.trtDesejado}</p></div>
              <span style={{background:"#FEF9C3",color:"#713F12",borderRadius:8,padding:"3px 10px",fontSize:".76rem",fontWeight:600,flexShrink:0}}>📍 {chatTarget.cidadeAtual}</span>
            </div>
            <div style={{flex:1,overflowY:"auto",padding:16,display:"flex",flexDirection:"column",gap:10}}>
              {messages.length===0&&<div style={{textAlign:"center",color:"#94A3B8",fontSize:".83rem",margin:"auto"}}><p>Nenhuma mensagem ainda.</p><p style={{marginTop:4}}>Inicie a conversa!</p></div>}
              {messages.map((m,i)=>{const mine=m.from===user.id;return(<div key={i} style={{display:"flex",justifyContent:mine?"flex-end":"flex-start"}}><div style={{maxWidth:"72%",padding:"9px 13px",borderRadius:mine?"14px 14px 4px 14px":"14px 14px 14px 4px",background:mine?"#2563EB":"#F1F5F9",color:mine?"white":"#0F172A",fontSize:".87rem"}}><p>{m.text}</p><p style={{fontSize:".65rem",opacity:.6,marginTop:3,textAlign:"right"}}>{ago(m.ts)}</p></div></div>);})}
              <div ref={botRef}/>
            </div>
            <div style={{padding:"11px 14px",borderTop:"1px solid #E2E8F0",display:"flex",gap:8}}>
              <input className="inp" style={{flex:1}} placeholder="Digite sua mensagem..." value={txt} onChange={e=>setTxt(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}/>
              <button className="bp" onClick={send} style={{padding:"9px 16px"}}>Enviar ↑</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

function PerfilTab({user,setUser,srvs,saveSrvs,showToast,myMatches}){
  const ex=srvs.find(s=>s.id===user.id);
  const [f,setF]=useState({nome:user.nome,cargo:user.cargo,senha:""});
  const upd=(k,v)=>setF(p=>({...p,[k]:v}));
  const save=async()=>{
    if(!f.nome||!f.cargo)return showToast("Preencha os campos.","erro");
    const updated={...user,nome:f.nome,cargo:f.cargo,...(f.senha?{senha:f.senha}:{})};
    const users=await DB.get("users:trt:2026",true)||{};users[user.id]=updated;await DB.set("users:trt:2026",users,true);await DB.set("auth:current:2026",updated);setUser(updated);
    if(ex)await saveSrvs(srvs.map(s=>s.id===user.id?{...s,nome:updated.nome,cargo:updated.cargo}:s));
    showToast("Perfil atualizado! ✓");
  };
  return(
    <div className="fi">
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,maxWidth:680,margin:"0 auto"}}>
        <div className="card" style={{padding:"24px",gridColumn:"1 / -1"}}>
          <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:20}}>
            <div style={{width:56,height:56,borderRadius:15,background:ac(user.nome),display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontWeight:800,fontSize:"1.2rem"}}>{ini(user.nome)}</div>
            <div><h2 style={{fontWeight:800,color:"#0F172A",fontSize:"1.05rem"}}>{user.nome}</h2><p style={{color:"#64748B",fontSize:".83rem"}}>{user.cargo}</p><p style={{color:"#94A3B8",fontSize:".75rem"}}>✉️ {user.email}</p></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <FL label="Nome completo"><input className="inp" value={f.nome} onChange={e=>upd("nome",e.target.value)}/></FL>
            <FL label="Cargo"><select className="inp" value={f.cargo} onChange={e=>upd("cargo",e.target.value)}>{CARGOS.filter(c=>c!=="Todos").map(o=><option key={o}>{o}</option>)}</select></FL>
            <FL label="Nova senha (opcional)"><input className="inp" type="password" placeholder="••••••••" value={f.senha} onChange={e=>upd("senha",e.target.value)}/></FL>
          </div>
          <button className="bp" onClick={save} style={{marginTop:16,padding:"11px 24px"}}>Salvar alterações</button>
        </div>
        <div className="card" style={{padding:"20px"}}>
          <h3 style={{fontWeight:700,color:"#0F172A",fontSize:".93rem",marginBottom:14}}>📌 Minha Permuta</h3>
          {ex?(<><p style={{fontSize:".8rem",color:"#1E3A8A",fontWeight:700,marginBottom:8}}>{ex.trtAtual} → {ex.trtDesejado}</p><span style={{background:"#FEF9C3",color:"#713F12",borderRadius:8,padding:"3px 10px",fontSize:".79rem",fontWeight:600}}>📍 {ex.cidadeAtual}</span><div style={{margin:"6px 0",color:"#94A3B8"}}>↓</div><span style={{background:"#DCFCE7",color:"#14532D",borderRadius:8,padding:"3px 10px",fontSize:".79rem",fontWeight:600}}>🎯 {ex.cidadesDesejadas}</span><p style={{marginTop:10,fontSize:".75rem",color:"#94A3B8"}}>Publicada {ago(ex.ts)}</p></>):<p style={{color:"#94A3B8",fontSize:".83rem"}}>Você ainda não publicou uma permuta.</p>}
        </div>
        <div className="card" style={{padding:"20px"}}>
          <h3 style={{fontWeight:700,color:"#0F172A",fontSize:".93rem",marginBottom:14}}>📊 Plataforma</h3>
          {[["Servidores cadastrados",srvs.length],["TRTs disponíveis",TRTS.length-1],["Meus matches",myMatches.length]].map(([l,v])=>(
            <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:"1px solid #F1F5F9"}}>
              <span style={{fontSize:".8rem",color:"#64748B"}}>{l}</span>
              <span style={{fontSize:".8rem",fontWeight:700,color:l==="Meus matches"&&v>0?"#059669":"#2563EB"}}>{v}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
